const crypto = require('crypto');
const signatureHeader = $request.headers['x-kiwify-signature'];
const secret = $env.KIWIFY_WEBHOOK_SECRET;

if (!secret) throw new Error('Security: KIWIFY_WEBHOOK_SECRET not configured');
if (!signatureHeader) throw new Error('Security Violation: Missing Signature');

const rawBody = $request.rawBody || JSON.stringify($json.body || $json);
const expected = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
const received = String(signatureHeader).replace(/^sha256=/, '');

if (received !== expected) throw new Error('Security Violation: Invalid Signature');
return $input.all();
